void MRFGreenProfileCmdDlg::Build()
{
	_pMainFrame = new CATDlgFrame(this, (const char*)"Frame_Main", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame | CATDlgGridLayout);
	_pMainFrame->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

	//---------------------Combo Frame---------------------//
	_pComboFrame = new CATDlgFrame(_pMainFrame, (const char*)"Frame_Combo", 0 | CATDlgFraNoTitle | CATDlgFraNoFrame | CATDlgGridLayout);
	_pComboFrame->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);

	_pLabelGreenProfileConfig = new CATDlgLabel(_pComboFrame, (const char*)"GreenProfile_TyreFeature", 0 | CATDlgLabLeft);
	_pLabelGreenProfileConfig->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);
	

	_pComboGreenProfileConfig = new CATDlgCombo(_pComboFrame, (const char*)"Combo_GreenProfileConfig", 0 | CATDlgCmbDropDown);
	_pComboGreenProfileConfig->SetGridConstraints(0,1, 1, 1, CATGRID_4SIDES);
	_pComboGreenProfileConfig->SetLine("No Selection");

	_pLabelSmoothenedInnerPro_Curve = new CATDlgLabel(_pComboFrame, (const char*)"Smoothened Inner Profile", 0 | CATDlgLabLeft);
	_pLabelSmoothenedInnerPro_Curve->SetGridConstraints(1, 0, 1, 1, CATGRID_4SIDES);

	_pSelectorListSmoothenedCurve = new CATDlgSelectorList(_pComboFrame, (const char*)"SelectorList_SmoothenedCurve", 0);
	_pSelectorListSmoothenedCurve->SetGridConstraints(1, 1, 1, 1, CATGRID_4SIDES);
	_pSelectorListSmoothenedCurve->SetVisibleTextHeight(1);
	_pSelectorListSmoothenedCurve->SetVisibleTextWidth(25);
	_pSelectorListSmoothenedCurve->SetLine("No Curve Is Found");

	//--------------------------------------------------//

	//----------------------MultiList Surface Frame-----------------------------------//
	_pMultiListSurfaceFrame = new CATDlgFrame(_pMainFrame, (const char*)"Frame_SurfaceProfile", 0  | CATDlgGridLayout | CATDlgFraNoFrame);
	_pMultiListSurfaceFrame->SetGridConstraints(1, 0, 3, 1, CATGRID_4SIDES);

	_pMultiListSurfaceProfile = new CATDlgMultiList(_pMultiListSurfaceFrame, (const char*)"Frame_ParameterEditable", 0);
	_pMultiListSurfaceProfile->SetGridConstraints(0, 0, 3, 1, CATGRID_4SIDES);

	CATUnicodeString strHeader[3];
	strHeader[0] = "S.No";
	strHeader[1] = "	Surfaces Name			  ";

	_pMultiListSurfaceProfile->SetColumnTitles(2, strHeader);
	_pMultiListSurfaceProfile->SetColumnTextWidth(0, 5);
	_pMultiListSurfaceProfile->SetColumnTextWidth(1, 30);
	_pMultiListSurfaceProfile->SetVisibleLineCount(10);
	_pMultiListSurfaceProfile->SetVisibleColumnCount(2);
	_pMultiListSurfaceProfile->SetTitlesVisibility(TRUE);

	//-------------------------------------------------------------//

	//---------------------------Multi List Param Frame-----------------------------------//
	_pMultiListOParamFrame = new CATDlgFrame(_pMainFrame, (const char*)"Frame_ParameterEditable", 0  | CATDlgGridLayout | CATDlgFraNoFrame);
	_pMultiListOParamFrame->SetGridConstraints(2, 0, 1, 1, CATGRID_4SIDES);

	_pMultiListParam = new CATDlgMultiList(_pMultiListOParamFrame, (const char*)"Frame_ParameterEditable", 0);
	_pMultiListParam->SetGridConstraints(0, 0, 1, 1, CATGRID_4SIDES);
	
	CATUnicodeString strHeader_2[3];
	strHeader_2[0] = "S.No";
	strHeader_2[1] = "Input Parameters Name";
	strHeader_2[2] = "Input Parameters Value";

	_pMultiListParam->SetColumnTitles(3, strHeader_2);
	_pMultiListParam->SetColumnTextWidth(0, 5);
	_pMultiListParam->SetColumnTextWidth(1, 15);
	_pMultiListParam->SetColumnTextWidth(2, 14);
	_pMultiListParam->SetVisibleLineCount(10);
	_pMultiListParam->SetVisibleColumnCount(3);
	_pMultiListParam->SetTitlesVisibility(TRUE);
	_pMultiListParam->SetColumnEditable(2, 1);
	//---------------------------------------------------------------//

	/*_pPushButtonCreateFeature = new CATDlgPushButton(_pMainFrame, (const char*)"Create Feature", 0);
	_pPushButtonCreateFeature->SetGridConstraints(3, 0, 1, 1, CATGRID_4SIDES);*/


}

